prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?idType WHERE {
  VALUES ?idType { "normalized" "original" }
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId "1cd93309017949fdbebf0f7d7ea50b4a" . BIND("normalized" AS ?idType) }
  OPTIONAL { ?model tai:originalId "1cd93309017949fdbebf0f7d7ea50b4a" . BIND("original" AS ?idType) }
  FILTER(BOUND(?idType))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gw ?gwName ?choreo ?choreoName WHERE {
  ?model a bboExt:Model .
  { ?model tai:normalizedId "1cd93309017949fdbebf0f7d7ea50b4a" . }
  UNION
  { ?model tai:originalId "1cd93309017949fdbebf0f7d7ea50b4a" . }

  ?model tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?gw a bboExt:EventBasedGateway .
  ?gw tai:belongsTo ?choreo .

  OPTIONAL { ?gw bbo:name ?gwName . }
  OPTIONAL { ?choreo bbo:name ?choreoName . }
}
ORDER BY ?choreoName ?gwName
LIMIT 25
